import React, { useEffect } from 'react'
import Home from './Home';

const Logout = () => {

    useEffect(() => {
      
        fetch('/logout',{
            method:'GET',
            headers:{
                "Content-Type":"application/json",
              },
        }).then(res=>{
            if(res.status!=200)
            {
                const error=new Error(res.error);
                throw error;
            }
        }).catch(err=>{
            console.log(err);
        });
      
    });
    

  return (
    <div>
        <Home />
    </div>
  )
}

export default Logout
